<?php namespace App\Repositories\Fee;use App\Repositories\BaseRepository;use App\Models\Fee\FeeStructure;use Illuminate\Database\Eloquent\Collection;use Illuminate\Pagination\LengthAwarePaginator;class FeeStructureRepository extends BaseRepository{    public function __construct(FeeStructure $model)    {        $this->model = $model;        parent::__construct($model);    }    public function findByClass(int $classId): Collection    {        return $this->findByField('class_id', $classId);    }    public function findByAcademicYear(int $academicYearId): Collection    {        return $this->findByField('academic_year_id', $academicYearId);    }    public function findByCategory(int $feeCategoryId): Collection    {        return $this->findByField('fee_category_id', $feeCategoryId);    }    public function findByClassAndYear(int $classId, int $academicYearId): ?FeeStructure    {        return $this->query()->where('class_id', $classId)->where('academic_year_id', $academicYearId)->first();    }    public function getActiveStructures(): Collection    {        return $this->query()->where('is_active', true)->get();    }    public function searchStructures(string $keyword): Collection    {        return $this->query()->where('name', 'like', "%{$keyword}%")->get();    }}